import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for indentation of class bodies when classes have multiline super type lists.
 * This test class specifically addresses the issues described in the GitHub issue about
 * incorrect indentation with ktlint_official code style.
 */
class IndentationRuleClassBodyTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a class without explicit constructor keyword but with multiline super type list - body should not be indented`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with explicit constructor keyword and multiline super type list - super type list should be indented properly`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                    BarFoo1,
                    BarFoo2 {
                    // body
                }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with explicit constructor keyword and multiline super type list with wrong indentation - should be corrected`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()
        val formattedCode =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                    BarFoo1,
                    BarFoo2 {
                    // body
                }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasLintViolations(
                com.pinterest.ktlint.test.LintViolation(6, 1, "Unexpected indentation (0) (should be 4)"),
                com.pinterest.ktlint.test.LintViolation(7, 1, "Unexpected indentation (0) (should be 4)"),
                com.pinterest.ktlint.test.LintViolation(8, 1, "Unexpected indentation (4) (should be 8)"),
                com.pinterest.ktlint.test.LintViolation(9, 1, "Unexpected indentation (0) (should be 4)"),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a class without explicit constructor keyword with single line super type - body should not be indented`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2) {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with explicit constructor keyword and single line super type - body should be indented`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2) {
                    // body
                }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class without explicit constructor and no super type - body should not be indented`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with explicit constructor and no super type - body should be indented`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) {
                    // body
                }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with multiline super type list but no parameters - body should not be indented`() {
        val code =
            """
            class Foo : FooBar(),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }
}
"}

